  "objectives": [],
  "questionProse": [
    "מה עושה הפונקציה `COALESCE` ב-SQL?"
  ],
  "hintsProse": [],
  "explanationProse": [
    "הפונקציה `COALESCE` מחזירה את הערך הראשון שאינו NULL ברשימה נתונה, שימושית להחלפת ערכי ברירת מחדל כאשר נתקלים ב-NULL.\n\n    לדוגמה, `COALESCE(column_name, 0)` תחזיר `0` אם `column_name` הוא `NULL`."
  ]
}
